void main(){vec2 v=vec2(float((gl_VertexID<<1)&2),float(gl_VertexID&2));gl_Position=vec4(v*2.-1.,0.,1.);}`;

  const FS = `#version 300 es
precision highp float;
out vec4 O;
uniform vec2 uR;
uniform float uT;
