    const dx = e.clientX - p[0], dy = e.clientY - p[1];
    ptrs.set(e.pointerId, [e.clientX, e.clientY]);
    if (ptrs.size === 1) {
      yaw -= dx * 0.008;
      pitch = clampP(pitch + dy * 0.008);
    } else if (ptrs.size === 2) {
      const a = [...ptrs.values()];
